<?php
require dirname(__DIR__) . '/src/bootstrap.php';
$user=require_admin();if($_SERVER['REQUEST_METHOD']!=='POST'){redirect('admin/inscripciones.php');}verify_csrf();$id=(int)($_POST['id']??0);$talla=trim((string)($_POST['talla']??''));$obs=trim((string)($_POST['observaciones']??''))?:null;
try{$pdo->beginTransaction();$s=$pdo->prepare('SELECT estado,codigo FROM inscripciones WHERE id=? FOR UPDATE');$s->execute([$id]);$r=$s->fetch();if(!$r||$r['estado']!=='pago_confirmado')throw new RuntimeException('Solo puede entregar kits de pagos confirmados.');$pdo->prepare('INSERT INTO entrega_kits (inscripcion_id,talla_entregada,entregado_por,observaciones) VALUES (?,?,?,?)')->execute([$id,$talla,$user['id'],$obs]);$pdo->prepare("UPDATE inscripciones SET estado='kit_entregado' WHERE id=?")->execute([$id]);audit($pdo,$user['id'],'entregar_kit','inscripcion',$id,['talla'=>$talla]);$pdo->commit();flash('success','Kit entregado correctamente.');}catch(Throwable $e){if($pdo->inTransaction())$pdo->rollBack();flash('danger',$e->getMessage());}redirect('admin/ver.php?id='.$id);
